<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('sales.view');$stage=vp3_input('stage');$q=vp3_input('q');$sql='SELECT l.*,a.name assigned_name,(SELECT COUNT(*) FROM proposals p WHERE p.lead_id=l.id) proposal_count FROM leads l LEFT JOIN admins a ON a.id=l.assigned_admin_id WHERE 1=1';$params=[];if($stage!==''){$sql.=' AND l.stage=?';$params[]=$stage;}if($q!==''){$sql.=' AND (l.name LIKE ? OR l.email LIKE ? OR l.company_name LIKE ? OR l.project_name LIKE ?)';$like='%'.$q.'%';array_push($params,$like,$like,$like,$like);}$sql.=' ORDER BY CASE WHEN l.next_follow_up_at IS NOT NULL AND l.next_follow_up_at<NOW() THEN 0 ELSE 1 END,l.next_follow_up_at,l.updated_at DESC LIMIT 250';$rows=[];$ready=false;try{$stmt=vp3_db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();$ready=true;}catch(Throwable){}$pageTitle='Sales Pipeline';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Sales and discovery</span><h1>Lead pipeline</h1><p>Qualify requests, schedule follow-up, prepare proposals, and convert approved work into projects.</p></div><a class="button" href="lead.php">Add lead</a></div><form class="admin-filter"><label>Stage<select name="stage"><option value="">All stages</option><?php foreach(['new','qualified','discovery','proposal','negotiation','won','lost','archived'] as $v):?><option <?=$stage===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Search<input name="q" value="<?=vp3_e($q)?>"></label><button class="button small">Filter</button></form><?php if(!$ready):?><div class="notice">Import the sales and creative operations migration.</div><?php else:?><div class="table-wrap"><table class="table"><thead><tr><th>Lead</th><th>Project</th><th>Stage</th><th>Priority</th><th>Assigned</th><th>Follow-up</th><th>Proposals</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><a href="lead.php?id=<?=(int)$r['id']?>"><strong><?=vp3_e($r['name'])?></strong></a><br><small><?=vp3_e($r['email'])?></small></td><td><?=vp3_e($r['project_name']?:$r['company_name']?:'—')?><br><small><?=vp3_e($r['project_type'])?></small></td><td><span class="badge <?=vp3_e($r['stage'])?>"><?=vp3_e($r['stage'])?></span></td><td><?=vp3_e($r['priority'])?></td><td><?=vp3_e($r['assigned_name']?:'Unassigned')?></td><td class="<?=vp3_e(vp3_due_state($r['next_follow_up_at']))?>"><?=vp3_e($r['next_follow_up_at']?:'—')?></td><td><?=(int)$r['proposal_count']?></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="7">No matching leads.</td></tr><?php endif;?></tbody></table></div><?php endif;?>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
